{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-compressor-mixed-parameter-patch-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的压缩机、分离器及其相连出口流的局部诊断生成候选提案，重点处理压缩机出口压力目标无效、压缩机防喘振参数缺失、分离器固定压力缺参，以及分离器气相出口未连接的问题。",
  "answers": [
    {
      "summary": "针对 compressor-22、separator-22 和 separator-gas-94 提出最小且可审查的局部补丁候选；其中参数补全可直接局部审查，未连接气相流仅建议增加连接占位，避免凭空指定下游对象。",
      "issues": [
        {
          "title": "压缩机出口压力目标低于入口压力",
          "details": "compressor-22 当前 control_mode 为 outlet_pressure，outlet_pressure_target_kpa=165，而入口流 feed-94 的 pressure_kpa=190，直接触发无效压力目标诊断。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "压缩机防喘振最小流量旁路百分比缺失",
          "details": "compressor-22 标记 anti_surge_review_required=true，但缺少 minimum flow bypass percent 参数。",
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        },
        {
          "title": "分离器固定压力模式缺少操作压力目标",
          "details": "separator-22 已配置 pressure_mode=fixed，但缺少固定压力目标参数。",
          "citations": [
            "diag-4",
            "flowdoc-unit-2"
          ]
        },
        {
          "title": "分离器气相出口未连接下游",
          "details": "separator-gas-94 当前没有 downstream consumer 或 export sink，且该路由仍依赖当前压缩机出口与分离器压力上下文，不能在缺乏更多对象证据时直接指定具体去向。",
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为压缩机出口压力目标提供高于入口压力的占位修正",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "现有 outlet_pressure_target_kpa 低于已知入口压力，无法满足压缩机升压逻辑。为保持补丁最小且不武断指定最终操作点，建议将现值替换为“高于入口压力”的占位约束，待人工按工艺目标确认具体数值。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "kind": "numeric_min_exclusive",
                "reference": {
                  "stream_id": "feed-94",
                  "path": "specs.pressure_kpa"
                },
                "unit": "kPa",
                "description": "设置为严格高于压缩机入口压力的出口压力目标"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为压缩机补充防喘振最小流量旁路百分比占位",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "诊断明确指出 anti-surge review 所需参数缺失。基于当前证据仅能建议补充参数占位，不应臆测具体百分比。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.minimum_flow_bypass_percent",
                "kind": "numeric_range",
                "unit": "%",
                "description": "补充防喘振审查所需的最小流量旁路百分比",
                "min": 0,
                "max": 100
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为固定压力分离器补充操作压力目标占位",
          "target": {
            "type": "unit",
            "id": "separator-22"
          },
          "rationale": "separator-22 处于 fixed pressure mode，但缺失对应压力目标。由于当前上下游压力上下文仍在变化，建议先增加局部压力参数占位，避免直接假定最终操作压力。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.operating_pressure_target_kpa",
                "kind": "numeric",
                "unit": "kPa",
                "description": "补充分离器固定压力模式所需的操作压力目标"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为未连接的分离器气相出口增加下游连接占位",
          "target": {
            "type": "stream",
            "id": "separator-gas-94"
          },
          "rationale": "该流存在明确的拓扑未完成错误，但当前请求未提供可合法连接的具体下游单元或外送端对象。为保持最小、可审查和非执行式，仅建议增加下游连接占位，交由人工选择最终去向。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "separator-gas-94",
              "open_end": "downstream",
              "allowed_connection_types": [
                "unit_inlet",
                "export_sink"
              ],
              "description": "为 Separator Gas 94 指定下游消费者或外送端"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.85,
      "citations": [
        "diag-2",
        "diag-3",
        "diag-4",
        "diag-1",
        "diag-6",
        "flowdoc-unit-1",
        "flowdoc-unit-2",
        "flowdoc-stream-1",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    }
  ]
}
